// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





// Place helper components here if needed

export default function Component(props: Props) {
  // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit');

  // State for form fields
  const [step, setStep] = useState(1);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfaction, setSatisfaction] = useState('');
  const [features, setFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');

  // Validation state
  const [nameError, setNameError] = useState('');
  const [emailError, setEmailError] = useState('');

  // Helper: Email validation
  const validateEmail = useCallback((value: string): boolean => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(value);
  }, []);

  // Validate name and email on change
  const validateName = useCallback((value: string) => {
    if (!value.trim()) {
      setNameError('Name is required');
      return false;
    }
    setNameError('');
    return true;
  }, []);

  const validateEmailField = useCallback((value: string) => {
    if (!value.trim()) {
      setEmailError('Email is required');
      return false;
    }
    if (!validateEmail(value)) {
      setEmailError('Please enter a valid email address');
      return false;
    }
    setEmailError('');
    return true;
  }, [validateEmail]);

  // Check if Step 1 is valid
  const isStep1Valid = useMemo(() => {
    return name.trim().length > 0 && validateEmail(email);
  }, [name, email, validateEmail]);

  // Check if Step 2 is valid
  const isStep2Valid = useMemo(() => {
    return satisfaction !== '';
  }, [satisfaction]);

  // Handle next button
  const handleNext = useCallback(() => {
    if (step === 1) {
      const nameValid = validateName(name);
      const emailValid = validateEmailField(email);
      if (!nameValid || !emailValid) return;
    }
    if (step < 5) {
       setStep(step + 1);
     }
  }, [step, name, email, validateName, validateEmailField]);

  // Handle back button
  const handleBack = useCallback(() => {
    if (step > 1) {
      setStep(step - 1);
    }
  }, [step]);

  // Handle submit
  const handleSubmit = useCallback(() => {
    submit({
      name: name.trim(),
      email: email.trim(),
      satisfaction: parseInt(satisfaction, 10),
      features,
      comments: comments.trim(),
    });
  }, [name, email, satisfaction, features, comments, submit]);

  // Handle feature checkbox toggle
  const toggleFeature = useCallback((feature: string) => {
    setFeatures((prev) =>
      prev.includes(feature) ? prev.filter((f) => f !== feature) : [...prev, feature]
    );
  }, []);

  const progressPercent = ((step - 1) / 4) * 100;

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Header with title and progress */}
        <Stack gap="var(--ggui-spacing-3)">
          <Heading level={1}>Multi-Step Survey</Heading>
          <Box>
            <Progress value={progressPercent} max={100} size="md" />
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)" style={{ marginTop: 'var(--ggui-spacing-2)' }}>
              Step {step === 5 ? 'Final Review' : step} of 5
            </Text>
          </Box>

        {/* Step 1: Name and Email */}
        {step === 1 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={2}>Personal Information</Heading>
              <Input
                label="Name"
                value={name}
                onChange={(value) => {
                  setName(value);
                  validateName(value);
                }}
                placeholder="Enter your full name"
                error={nameError}
                required
              />
              <Input
                label="Email"
                type="email"
                value={email}
                onChange={(value) => {
                  setEmail(value);
                  validateEmailField(value);
                }}
                placeholder="you@example.com"
                error={emailError}
                required
              />
            </Stack>
          </Card>
        )}

        {/* Step 2: Satisfaction Rating */}
        {step === 2 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={2}>How satisfied are you?</Heading>
              <RadioGroup
                label="Satisfaction Rating"
                value={satisfaction}
                onChange={setSatisfaction}
                options={props.satisfactionLabels.map((label, idx) => ({
                  value: String(idx + 1),
                  label,
                }))}
                direction="vertical"
              />
            </Stack>
          </Card>
        )}

        {/* Step 3: Feature Interests */}
        {step === 3 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={2}>Which features interest you?</Heading>
              <Stack gap="var(--ggui-spacing-3)">
                {props.featureOptions.map((feature) => (
                  <Checkbox
                    key={feature}
                    label={feature}
                    checked={features.includes(feature)}
                    onChange={() => toggleFeature(feature)}
                  />
                ))}
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Step 4: Comments */}
        {/* Step 4: Comments */}
        {step === 4 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={2}>Additional Comments</Heading>
              <TextArea
                label="Comments"
                value={comments}
                onChange={setComments}
                placeholder="Tell us what you think..."
                rows={6}
                maxLength={500}
                showCount
              />
            </Stack>
           </Card>
         )}
        {/* Step 5: Final Review */}
        {step === 5 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={2}>Review Your Answers</Heading>
              <Box padding="var(--ggui-spacing-4)" background="var(--ggui-color-surfaceVariant)" borderRadius="var(--ggui-shape-radius-md)">
                <Stack gap="var(--ggui-spacing-3)">
                  <Stack direction="horizontal" justify="between">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Name</Text>
                    <Text>{name}</Text>
                  </Stack>
                  <Divider margin="0" />
                  <Stack direction="horizontal" justify="between">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Email</Text>
                    <Text>{email}</Text>
                  </Stack>
                  <Divider margin="0" />
                  <Stack direction="horizontal" justify="between">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Satisfaction</Text>
                    <Text>{satisfaction ? props.satisfactionLabels[parseInt(satisfaction, 10) - 1] : 'Not selected'}</Text>
                  </Stack>
                  <Divider margin="0" />
                  <Stack direction="horizontal" justify="between">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Features of Interest</Text>
                    <Text>{features.length > 0 ? features.join(', ') : 'None selected'}</Text>
                  </Stack>
                  <Divider margin="0" />
                  <Stack gap="var(--ggui-spacing-2)">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Comments</Text>
                    <Text>{comments || '(No comments provided)'}</Text>
                  </Stack>
                </Stack>
              </Box>
            </Stack>
          </Card>
        )}

        {/* Navigation Buttons */}
        <Row justify="between" gap="var(--ggui-spacing-3)">
          <Button
            variant="outline"
            onClick={handleBack}
            disabled={step === 1}
          >
            Back
          </Button>
          {step < 5 ? (
            <Button
              variant="primary"
              onClick={handleNext}
              disabled={(step === 1 && !isStep1Valid) || (step === 2 && !isStep2Valid)}
            >
              Next
            </Button>
          ) : (
            <Button
              variant="primary"
              onClick={handleSubmit}
            >
              Submit
            </Button>
          )}
        </Row>
       </Stack>
     </Container>
   );
 }

