  const taskChanged = useStream<StreamTaskChanged>('taskChanged'); // A task was moved, edited, or created by another user — update it in the board

  // Local task management with stream updates
  const [localTasks, setLocalTasks] = useState<Props['tasks']>(props.tasks);
  const [addingTaskColumn, setAddingTaskColumn] = useState<string | null>(null);
