  // Sync stream updates with local state
  useEffect(() => {
    if (taskChanged.latest && taskChanged.latest.task) {
      const updatedTask = taskChanged.latest.task;
      setLocalTasks(prev => {
        const taskIdx = prev.findIndex(t => t.id === updatedTask.id);
        if (taskIdx >= 0) {
          const newTasks = [...prev];
          newTasks[taskIdx] = { ...newTasks[taskIdx], ...updatedTask };
          return newTasks;
        }
        if (taskChanged.latest?.action === 'create') {
          return [...prev, updatedTask];
        }
        return prev;
      });
    }
  }, [taskChanged.latest]);

