    setLocalTasks(prev => prev.map(t => t.id === taskId ? { ...t, column: newColumnId } : t));
    taskUpdate({ action: 'move', taskId, data: { column: newColumnId } });
  }, [taskUpdate]);

   const handleEditTask = useCallback((updatedTask: Props['tasks'][0]) => {
     setLocalTasks(prev => prev.map(t => t.id === updatedTask.id ? updatedTask : t));
     taskUpdate({ action: 'edit', taskId: updatedTask.id || '', data: { column: updatedTask.column || '', title: updatedTask.title || '' } });
   }, [taskUpdate]);

   const handleAddTask = useCallback((columnId: string) => {
     if (!newTaskTitle.trim()) return;
     const newTask: Props['tasks'][0] = {
       id: `task-${Date.now()}`,
       title: newTaskTitle,
       priority: newTaskPriority,
       column: columnId,
       assignee: '',
       dueDate: '',
     };
     setLocalTasks(prev => [...prev, newTask]);
     taskUpdate({ action: 'create', taskId: newTask.id || '', data: { column: columnId, title: newTaskTitle } });
     setNewTaskTitle('');
     setNewTaskPriority('medium');
     setAddingTaskColumn(null);
   }, [newTaskTitle, newTaskPriority, taskUpdate]);

  // Compute column summaries
  const columnStats = useMemo(() => {
    return props.columns.map(col => {
      const tasks = localTasks.filter(t => t.column === col.id);
      const completedCount = tasks.length > 0 && col.id === 'done' ? tasks.length : 0;
      return { columnId: col.id, total: tasks.length, completed: completedCount };
    });
  }, [props.columns, localTasks]);

  const totalTasks = useMemo(() => localTasks.length, [localTasks]);
  const completedTasks = useMemo(() => localTasks.filter(t => t.column === 'done').length, [localTasks]);

  return (
