              </Box>
              <Divider orientation="vertical" margin="0" />
              <Box>
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                  Completed
                </Text>
                <Heading level={3} color="var(--ggui-color-success-600)">{completedTasks}</Heading>
              </Box>
            </Stack>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
              {totalTasks === 0 ? 'No tasks' : `${Math.round((completedTasks / totalTasks) * 100)}% complete`}
            </Text>
          </Row>
        </Card>

        {/* Kanban board */}
        <Row gap="var(--ggui-spacing-4)" align="start">
          {props.columns && props.columns.map((column) => {
            const columnTasks = localTasks.filter(t => t.column === column.id);
            return (
               <Box key={column.id} style={{ flex: '0 1 calc(100% / 3)', minWidth: 'var(--ggui-spacing-10)' }}>
                <Card padding="var(--ggui-spacing-4)" shadow="sm" radius="md">
                  <Stack gap="var(--ggui-spacing-3)">
                    {/* Column header */}
                    <Box>
                      <Row gap="var(--ggui-spacing-2)" align="center" justify="between">
                        <Heading level={4}>{column.name}</Heading>
                        <Badge variant="secondary" size="sm">
                          {columnTasks.length}
                        </Badge>
                      </Row>
                    </Box>

                    <Divider orientation="horizontal" margin="var(--ggui-spacing-3)" />

                    {/* Task list */}
                    <Stack gap="var(--ggui-spacing-2)">
                      {columnTasks.length === 0 ? (
                        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)" align="center" is="span">
                          No tasks
                        </Text>
                      ) : (
                        columnTasks.map(task => (
                          <TaskCard
                            key={task.id}
