                            columns={props.columns}
                            onMove={handleMoveTask}
                            onEdit={handleEditTask}
                          />
                        ))
                      )}
                    </Stack>

                    <Divider orientation="horizontal" margin="var(--ggui-spacing-3)" />

                    {/* Add task button / form */}
                     {addingTaskColumn === column.id ? (
                       <Card padding="var(--ggui-spacing-3)" shadow="sm" radius="sm" border={true}>
                         <Stack gap="var(--ggui-spacing-2)">
