export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  // Actions — fire-and-forget to agent
  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage'); // Called when user sends a message. Payload: { text, timestamp }

  // Streams — real-time from agent (.latest, .all)
  const message = useStream<StreamMessage>('message'); // New message from another participant — append to message list
  const typing = useStream<StreamTyping>('typing'); // Typing indicator — show/hide based on active flag

  // State management
  const [messageText, setMessageText] = useState('');
  const [allMessages, setAllMessages] = useState<Array<{ sender?: string; text?: string; timestamp?: string }>>(props.messages);
  const [activeTyping, setActiveTyping] = useState<{ sender?: string } | null>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Auto-scroll to bottom when new messages arrive
  const scrollToBottom = useCallback(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, []);

  useEffect(() => {
    scrollToBottom();
  }, [allMessages, scrollToBottom]);

  // Handle new messages from stream
  useEffect(() => {
    if (message.latest) {
      setAllMessages((prev) => [...prev, message.latest!]);
    }
  }, [message.latest]);

  // Handle typing indicator from stream
  useEffect(() => {
    if (typing.latest) {
      if (typing.latest.active) {
        setActiveTyping({ sender: typing.latest.sender });
      } else {
        setActiveTyping(null);
      }
    }
  }, [typing.latest]);

  // Handle message submission
  const handleSendMessage = useCallback(() => {
    if (messageText.trim()) {
      sendMessage({
        text: messageText,
        timestamp: new Date().toISOString(),
      });
      setMessageText('');
    }
  }, [messageText, sendMessage]);

  // Handle Enter key for sending
  const handleKeyDown = useCallback(
    (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
      if (e.key === 'Enter' && !e.shiftKey) {
        e.preventDefault();
        handleSendMessage();
      }
    },
    [handleSendMessage]
  );

  // Group consecutive messages from the same sender
  const groupedMessages = useMemo(() => {
    const groups: Array<{
      sender?: string;
      messages: Array<{ text?: string; timestamp?: string }>;
    }> = [];

    allMessages.forEach((msg) => {
      const lastGroup = groups[groups.length - 1];
      if (lastGroup && lastGroup.sender === msg.sender) {
        lastGroup.messages.push({ text: msg.text, timestamp: msg.timestamp });
      } else {
        groups.push({
          sender: msg.sender,
          messages: [{ text: msg.text, timestamp: msg.timestamp }],
        });
      }
    });

    return groups;
  }, [allMessages]);

  // Format timestamp
  const formatTimestamp = (ts?: string) => {
    if (!ts) return '';
    try {
      const date = new Date(ts);
      return date.toLocaleTimeString([], {
        hour: '2-digit',
        minute: '2-digit',
      });
    } catch {
      return ts;
    }
  };

  const isCurrentUser = (sender?: string) => sender === props.currentUser;

  return (
    <Card
      shadow="lg"
      padding="0"
      radius="lg"
      border={true}
      style={{
        display: 'flex',
        flexDirection: 'column',
