          justifyContent: 'space-between',
          alignItems: 'center',
        }}
      >
        <Stack direction="vertical" gap="var(--ggui-spacing-1)" align="start">
          <Heading level={3} color="var(--ggui-color-onSurface)">
            {props.title}
          </Heading>
        </Stack>
        <Badge variant="primary" size="sm">
          {props.participantCount} participant{props.participantCount !== 1 ? 's' : ''}
        </Badge>
      </Box>

      {/* Message List */}
      <Stack
        direction="vertical"
        gap="var(--ggui-spacing-3)"
        align="stretch"
        style={{
          flex: 1,
          overflowY: 'auto',
          padding: 'var(--ggui-spacing-4)',
        }}
      >
        {groupedMessages.length === 0 ? (
          <Box
            style={{
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              height: '100%',
            }}
          >
            <Text
              color="var(--ggui-color-onSurfaceVariant)"
              variant="body"
              align="center"
            >
              No messages yet. Start the conversation!
            </Text>
          </Box>
        ) : (
          <>
            {groupedMessages.map((group, groupIdx) => {
              const isUser = isCurrentUser(group.sender);
              return (
                <Stack
                  key={`group-${groupIdx}`}
                  direction="vertical"
                  gap="var(--ggui-spacing-2)"
                  align={isUser ? 'end' : 'start'}
                  style={{
