                    alignSelf: isUser ? 'flex-end' : 'flex-start',
                  }}
                >
                  {!isUser && (
                    <Text
                      variant="label"
                      color="var(--ggui-color-onSurfaceVariant)"
                      size="sm"
                    >
                      {group.sender}
                    </Text>
                  )}
                  {group.messages.map((msg, msgIdx) => (
                    <Card
                      key={`msg-${groupIdx}-${msgIdx}`}
                      padding="var(--ggui-spacing-3)"
                      shadow="sm"
                      radius="md"
                      border={!isUser}
                      style={{
                        background: isUser
                          ? 'var(--ggui-color-primary-600)'
                          : 'var(--ggui-color-surfaceVariant)',
                        wordWrap: 'break-word',
                        overflowWrap: 'break-word',
                      }}
                    >
                      <Stack direction="vertical" gap="var(--ggui-spacing-1)">
