  // State: manage displayed stocks and last update timestamp
  const [displayedStocks, setDisplayedStocks] = useState(props.stocks || []);
  const [lastUpdated, setLastUpdated] = useState(new Date());
  const [flashingSymbols, setFlashingSymbols] = useState<Set<string>>(new Set());

  // Merge price updates from stream into displayed stocks
  useEffect(() => {
    if (priceUpdate.latest) {
      const update = priceUpdate.latest;
      setDisplayedStocks((prev) =>
        prev.map((stock) => {
          if (stock.symbol === update.symbol) {
            // Mark for flashing animation
            setFlashingSymbols((prevFlashing) => {
              const newFlashing = new Set(prevFlashing);
              newFlashing.add(update.symbol || '');
              // Auto-remove after animation
              setTimeout(() => {
                setFlashingSymbols((s) => {
                  const updated = new Set(s);
                  updated.delete(update.symbol || '');
                  return updated;
                });
              }, 600);
              return newFlashing;
            });

            return {
              ...stock,
              price: update.price ?? stock.price,
              change: update.change ?? stock.change,
              changePercent: update.changePercent ?? stock.changePercent,
            };
          }
          return stock;
        })
      );
      setLastUpdated(new Date());
    }
  }, [priceUpdate.latest]);

  // Update last updated timestamp in real-time
  useEffect(() => {
    const interval = setInterval(() => {
      setLastUpdated(new Date());
    }, 1000);
    return () => clearInterval(interval);
  }, []);

  // Format time for display
  const formatTime = (date: Date) => {
    return date.toLocaleTimeString('en-US', {
      hour: '2-digit',
      minute: '2-digit',
      second: '2-digit',
      hour12: true,
    });
  };

  // Determine market status display
  const currentMarketStatus = marketStatus.latest?.status || 'closed';
  const statusColor =
    currentMarketStatus === 'open'
      ? 'var(--ggui-color-success-600)'
      : currentMarketStatus === 'pre-market' || currentMarketStatus === 'after-hours'
        ? 'var(--ggui-color-warning-600)'
        : 'var(--ggui-color-error-600)';

  return (
    <Container maxWidth="2xl" padding="var(--ggui-spacing-6)">
      <MotionKeyframes />
      <Stack gap="var(--ggui-spacing-6)">
