            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
              Last Updated
            </Text>
            <Text variant="body" weight="medium" color="var(--ggui-color-onSurface)" aria-live="polite" aria-atomic="true">
              {formatTime(lastUpdated)}
            </Text>
            <Row gap="var(--ggui-spacing-1)" align="center">
              <Badge
                variant={
                  currentMarketStatus === 'open'
                    ? 'success'
                    : currentMarketStatus === 'pre-market' || currentMarketStatus === 'after-hours'
                      ? 'warning'
                      : 'error'
                }
                size="sm"
              >
                {currentMarketStatus.charAt(0).toUpperCase() + currentMarketStatus.slice(1)}
