                    </Row>
                  </Stack>
                </Stack>
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Navigation Buttons */}
        <Row gap="var(--ggui-spacing-3)" justify="between" style={{ width: '100%' }}>
          <Button
            variant="outline"
            onClick={handleBack}
            disabled={currentStep === 1}>
