  const currentIcon = useMemo(() => getConditionIcon(props.condition), [props.condition]);
  const safeForecast = useMemo(() => (Array.isArray(props.forecast) ? props.forecast.slice(0, 5) : []), [props.forecast]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-4)">
        <Card padding="var(--ggui-spacing-6)" shadow="md" radius="lg">
