                </Text>
                <Heading level={2} color="var(--ggui-color-onSurface)">
                  {props.city}
                </Heading>
                <Row align="center" gap="var(--ggui-spacing-2)">
                  <Text size="4xl" weight="bold" color="var(--ggui-color-primary-700)">
                    {formatTemp(props.temperature, props.unit)}
                  </Text>
