                    {currentIcon}
                  </Text>
                </Row>
                <Text variant="bodyLarge" color="var(--ggui-color-onSurfaceVariant)">
                  {props.condition}
                </Text>
              </Stack>

              <Card padding="var(--ggui-spacing-4)" border radius="md" shadow="none">
                <Stack gap="var(--ggui-spacing-3)">
