                  </Row>
                </Stack>
              </Card>
            </Row>

            <Divider margin="var(--ggui-spacing-2)" color="var(--ggui-color-outlineVariant)" />

            <Stack gap="var(--ggui-spacing-2)">
              <Heading level={3} color="var(--ggui-color-onSurface)">
                5-Day Forecast
              </Heading>
              {safeForecast.length === 0 ? (
                <Alert variant="info" title="No forecast available">
                  Forecast data is currently unavailable.
                </Alert>
              ) : (
                <Row gap="var(--ggui-spacing-2)" wrap>
                  {safeForecast.map((item, index) => {
                    const dayLabel = item.day || `Day ${index + 1}`;
                    const isSelected = selectedDay === dayLabel;
                    const icon = item.icon || getConditionIcon(props.condition);

                    return (
                      <Button
                        key={`${dayLabel}-${index}`}
                        variant="ghost"
                        size="sm"
                        onClick={() => setSelectedDay(dayLabel)}
                        style={{
                          padding: 'var(--ggui-spacing-3)',
                          borderRadius: 'var(--ggui-shape-radius-md)',
                          background: isSelected
                            ? 'var(--ggui-color-primary-100)'
