import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





// Place helper components here if needed

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object
  const [step, setStep] = useState<number>(1);
  const [name, setName] = useState<string>('');
  const [email, setEmail] = useState<string>('');
  const [satisfaction, setSatisfaction] = useState<string>('');
  const [features, setFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState<string>('');
  const [touched, setTouched] = useState<{ name: boolean; email: boolean }>({ name: false, email: false });
  const [submitted, setSubmitted] = useState<boolean>(false);

  const safeFeatureOptions = Array.isArray(props.featureOptions) ? props.featureOptions : [];
  const safeSatisfactionLabels = Array.isArray(props.satisfactionLabels) ? props.satisfactionLabels : [];

  const emailValid = useMemo(() => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email.trim()), [email]);
  const nameError = touched.name && name.trim().length === 0 ? 'Name is required' : '';
  const emailError = touched.email && email.trim().length === 0 ? 'Email is required' : touched.email && !emailValid ? 'Enter a valid email address' : '';

  const step1Valid = name.trim().length > 0 && emailValid;
  const step2Valid = satisfaction !== '';
  const canProceed = step === 1 ? step1Valid : step === 2 ? step2Valid : true;

  const progressValue = useMemo(() => (step / 4) * 100, [step]);

  const satisfactionOptions = useMemo(
    () =>
      safeSatisfactionLabels.map((label, index) => ({
        value: String(index + 1),
        label,
      })),
    [safeSatisfactionLabels],
  );

  const toggleFeature = useCallback((feature: string, checked: boolean) => {
    setFeatures((prev) => {
      if (checked) {
        if (prev.includes(feature)) {
          return prev;
        }
        return [...prev, feature];
      }
      return prev.filter((f) => f !== feature);
    });
  }, []);

  const goNext = useCallback(() => {
    if (!canProceed) {
      if (step === 1) {
        setTouched({ name: true, email: true });
      }
      return;
    }
    setStep((prev) => (prev < 4 ? prev + 1 : prev));
  }, [canProceed, step]);

  const goBack = useCallback(() => {
    setStep((prev) => (prev > 1 ? prev - 1 : prev));
  }, []);

  const [submitError, setSubmitError] = useState<string>('');

  const handleSubmit = useCallback(() => {
    const payload: ActionSubmitPayload = {
      name: name.trim(),
      email: email.trim(),
      satisfaction: Number(satisfaction),
      features,
      comments: comments.trim(),
    };
    try {
      setSubmitError('');
      submit(payload);
      setSubmitted(true);
    } catch (error) {
      setSubmitted(false);
      setSubmitError(error instanceof Error ? error.message : 'Failed to submit survey. Please try again.');
    }
  }, [comments, email, features, name, satisfaction, submit]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-5)" border shadow="sm">
          <Stack gap="var(--ggui-spacing-3)">
            <Row justify="between" align="center">
              <Heading level={3}>Survey</Heading>
              <Badge variant="primary">Step {step} of 4</Badge>
            </Row>
            <Progress value={progressValue} max={100} variant="default" size="md" />
          </Stack>
        </Card>

        <Card padding="var(--ggui-spacing-6)" border shadow="sm">
          <Stack gap="var(--ggui-spacing-4)">
            {step === 1 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Your details</Heading>
                <Input
                  label="Name"
                  value={name}
                  onChange={(value) => {
                    setName(value);
                    if (!touched.name) setTouched((prev) => ({ ...prev, name: true }));
                  }}
                  required
                  error={nameError || undefined}
                  placeholder="Enter your name"
                />
                <Input
                  label="Email"
                  type="email"
                  value={email}
                  onChange={(value) => {
                    setEmail(value);
                    if (!touched.email) setTouched((prev) => ({ ...prev, email: true }));
                  }}
                  required
                  error={emailError || undefined}
                  placeholder="you@example.com"
                />
              </Stack>
            )}

            {step === 2 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Satisfaction rating</Heading>
                <RadioGroup
                  label="How satisfied are you?"
                  value={satisfaction}
                  onChange={setSatisfaction}
                  options={satisfactionOptions}
                  direction="vertical"
                  error={!step2Valid ? 'Please select a rating to continue.' : undefined}
                />
              </Stack>
            )}

            {step === 3 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Feature interests</Heading>
                <Text color="var(--ggui-color-onSurfaceVariant)">Select all that apply.</Text>
                {safeFeatureOptions.length === 0 ? (
                  <Alert variant="info" title="No features available">
                    There are currently no feature options to choose from.
                  </Alert>
                ) : (
                  <Stack gap="var(--ggui-spacing-2)">
                    {safeFeatureOptions.map((feature) => (
                      <Checkbox
                        key={feature}
                        label={feature}
                        checked={features.includes(feature)}
                        onChange={(checked) => toggleFeature(feature, checked)}
                      />
                    ))}
                  </Stack>
                )}
              </Stack>
            )}

            {step === 4 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Additional comments</Heading>
                <TextArea
                  label="Comments (optional)"
                  value={comments}
                  onChange={setComments}
                  rows={6}
                  maxLength={500}
                  showCount
                  helperText="Share any additional feedback (max 500 characters)."
                  placeholder="Type your comments..."
                />
              </Stack>
            )}

            {step === 4 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Review your answers</Heading>
                <Card padding="var(--ggui-spacing-4)" border shadow="none">
                  <Stack gap="var(--ggui-spacing-2)">
                    <Text><Text is="span" weight="semibold">Name:</Text> {name || '—'}</Text>
                    <Text><Text is="span" weight="semibold">Email:</Text> {email || '—'}</Text>
                    <Text>
                      <Text is="span" weight="semibold">Satisfaction:</Text>{' '}
                      {satisfaction !== '' && safeSatisfactionLabels[Number(satisfaction) - 1]
                        ? `${satisfaction} - ${safeSatisfactionLabels[Number(satisfaction) - 1]}`
                        : '—'}
                    </Text>
                    <Text>
                      <Text is="span" weight="semibold">Interested features:</Text>{' '}
                      {features.length > 0 ? features.join(', ') : 'None selected'}
                    </Text>
                    <Text>
                      <Text is="span" weight="semibold">Comments:</Text>{' '}
                      {comments.trim().length > 0 ? comments.trim() : 'No comments'}
                    </Text>
                  </Stack>
                </Card>
                {submitError && (
                  <Alert variant="error" title="Submission failed">
                    {submitError}
                  </Alert>
                )}
                {submitted && !submitError && (
                  <Alert variant="success" title="Submitted">
                    Thank you! Your survey response has been submitted.
                  </Alert>
                )}
              </Stack>
            )}
            <Divider margin="var(--ggui-spacing-2)" />

            <Row justify="between" align="center">
              <Button variant="ghost" onClick={goBack} disabled={step === 1}>
                Back
              </Button>
              {step < 4 ? (
                <Button variant="primary" onClick={goNext} disabled={!canProceed}>
                  Next
                </Button>
              ) : (
                <Button variant="primary" onClick={handleSubmit}>
                  Submit
                </Button>
              )}
            </Row>
          </Stack>
        </Card>
      </Stack>
    </Container>

  );
}

