type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };




// Place helper components here if needed
const PRIORITY_OPTIONS = [
  { value: 'low', label: 'Low' },
  { value: 'medium', label: 'Medium' },
  { value: 'high', label: 'High' },
];

function getPriorityVariant(priority?: 'low' | 'medium' | 'high'): 'success' | 'warning' | 'error' | 'default' {
  if (priority === 'high') return 'error';
  if (priority === 'medium') return 'warning';
  if (priority === 'low') return 'success';
  return 'default';
}

function getInitials(name?: string): string {
  if (!name) return 'NA';
  const parts = name.trim().split(' ').filter(Boolean);
  if (parts.length === 0) return 'NA';
  if (parts.length === 1) return parts[0].slice(0, 2).toUpperCase();
  return `${parts[0][0] ?? ''}${parts[1][0] ?? ''}`.toUpperCase();
}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate'); // Called when a task is moved, edited, or created. Payload: { action, taskId, data }

  // Streams — real-time from agent (.latest, .all)
  const taskChanged = useStream<StreamTaskChanged>('taskChanged'); // A task was moved, edited, or created by another user — update it in the board

  const [tasksState, setTasksState] = useState<Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>>(props.tasks ?? []);
  const [addFormColumnId, setAddFormColumnId] = useState<string | null>(null);
  const [actionError, setActionError] = useState<string>('');
  const [newTaskTitle, setNewTaskTitle] = useState<string>('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [editingTitle, setEditingTitle] = useState<string>('');

  useEffect(() => {
    setTasksState(props.tasks ?? []);
  }, [props.tasks]);

  useEffect(() => {
    if (!taskChanged.latest || !taskChanged.latest.task?.id) return;
    const incoming = taskChanged.latest.task;
    const action = taskChanged.latest.action;

    setTasksState((prev) => {
      if (action === 'delete') {
        return prev.filter((t) => t.id !== incoming.id);
      }

      const existingIndex = prev.findIndex((t) => t.id === incoming.id);
      if (existingIndex === -1) {
        return [...prev, incoming];
      }

      const updated = [...prev];
      updated[existingIndex] = { ...updated[existingIndex], ...incoming };
      return updated;
    });
  }, [taskChanged.latest]);

  const columnList = useMemo(() => props.columns ?? [], [props.columns]);

  const totalTasks = tasksState.length;
  const completedCount = tasksState.filter((task) => task.column === 'done').length;

  const moveTask = useCallback(
    (taskId: string, nextColumn: string) => {
      try {
        setTasksState((prev) => prev.map((task) => (task.id === taskId ? { ...task, column: nextColumn } : task)));
        taskUpdate({ action: 'move', taskId, data: { column: nextColumn } });
        setActionError('');
      } catch (_error) {
        setActionError('Unable to move task. Please try again.');
      }
    },
    [taskUpdate]
  );

  const startEditTask = useCallback((taskId: string, currentTitle?: string) => {
    setEditingTaskId(taskId);
    setEditingTitle(currentTitle ?? '');
  }, []);

  const saveEditTask = useCallback(
    (taskId: string) => {
      const safeTitle = editingTitle.trim();
      if (!safeTitle) return;
      try {
        setTasksState((prev) => prev.map((task) => (task.id === taskId ? { ...task, title: safeTitle } : task)));
        taskUpdate({ action: 'edit', taskId, data: { column: '', title: safeTitle } as { column: string } });
        setActionError('');
      } catch (_error) {
        setActionError('Unable to save task changes. Please try again.');
      }
      setEditingTaskId(null);
      setEditingTitle('');
    },
    [editingTitle, taskUpdate]
  );

  const createTask = useCallback(
    () => {
      const title = newTaskTitle.trim();
      if (!title) return;
      const createdId = `task-${Date.now()}`;
      const createdTask = {
        id: createdId,
        title,
        priority: newTaskPriority,
        assignee: '',
        column: 'todo',
        dueDate: '',
      } as { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string };
      try {
        setTasksState((prev) => [...prev, createdTask]);
        taskUpdate({ action: 'create', taskId: createdId, data: { column: 'todo', title, priority: newTaskPriority, assignee: '', dueDate: '' } as { column: string } });
        setActionError('');
      } catch (_error) {
        setActionError('Unable to create task. Please try again.');
      }
      setNewTaskTitle('');
      setNewTaskPriority('medium');
      setAddFormColumnId(null);
    },
    [newTaskPriority, newTaskTitle, taskUpdate]
  );

  const tasksByColumn = useMemo(() => {
    const grouped: Record<string, Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>> = {};
    columnList.forEach((column) => {
      if (column.id) grouped[column.id] = [];
    });
    tasksState.forEach((task) => {
      const key = task.column ?? 'todo';
      if (!grouped[key]) grouped[key] = [];
      grouped[key].push(task);
    });
    return grouped;
  }, [columnList, tasksState]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-4)" shadow="sm" border>
          <Row justify="between" align="center" wrap>
            <Stack gap="var(--ggui-spacing-1)">
              <Heading level={1}>Team Task Board</Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                Real-time updates: {taskChanged.all.length}
              </Text>
            </Stack>
            <Row gap="var(--ggui-spacing-4)">
              <Badge variant="primary">Total: {totalTasks}</Badge>
              <Badge variant="success">Completed: {completedCount}</Badge>
            </Row>
          </Row>
        </Card>

        {columnList.length === 0 && (
          <Alert variant="info" title="No columns configured">
            Add columns in props.columns to render the Kanban board.
          </Alert>
        )}

        <CardGrid columns={{ sm: 1, md: 2, lg: 3 }} gap={16}>
          {columnList.map((column) => {
            const columnId = column.id ?? 'unknown';
            const columnTasks = tasksByColumn[columnId] ?? [];
            return (
              <Card key={columnId} padding="var(--ggui-spacing-4)" shadow="sm" border>
                <Stack gap="var(--ggui-spacing-4)">
                  <Row justify="between" align="center">
                    <Heading level={2}>{column.name ?? 'Untitled Column'}</Heading>
                    <Badge variant="default">{columnTasks.length}</Badge>
                  </Row>

                  <Stack gap="var(--ggui-spacing-3)">
                    {columnTasks.length === 0 && (
                      <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                        No tasks yet.
                      </Text>
                    )}

                    {columnTasks.map((task) => {
                      const taskId = task.id ?? `missing-${Math.random()}`;
                      return (
                        <Card key={taskId} padding="var(--ggui-spacing-3)" shadow="none" border>
                          <Stack gap="var(--ggui-spacing-2)">
                            <Row justify="between" align="start">
                              {editingTaskId === task.id ? (
                                <Input
                                  label="Edit task title"
                                  value={editingTitle}
                                  onChange={setEditingTitle}
                                  placeholder="Task title"
                                />
                              ) : (
                                <Button
                                  variant="ghost"
                                  size="sm"
                                  onClick={() => task.id && startEditTask(task.id, task.title)}
                                >
                                  {task.title ?? 'Untitled task'}
                                </Button>
                              )}
                              {editingTaskId === task.id ? (
                                <Row gap="var(--ggui-spacing-2)">
                                  <Button variant="primary" size="sm" onClick={() => task.id && saveEditTask(task.id)}>
                                    Save
                                  </Button>
                                  <Button
                                    variant="ghost"
                                    size="sm"
                                    onClick={() => {
                                      setEditingTaskId(null);
                                      setEditingTitle('');
                                    }}
                                  >
                                    Cancel
                                  </Button>
                                </Row>
                              ) : (
                                <Button
                                  variant="ghost"
                                  size="sm"
                                  onClick={() => task.id && startEditTask(task.id, task.title)}
                                >
                                  Edit
                                </Button>
                              )}
                            </Row>

                            <Row gap="var(--ggui-spacing-2)" align="center" wrap>
                              <Badge variant={getPriorityVariant(task.priority)}>{task.priority ?? 'none'}</Badge>
                              <Avatar name={task.assignee || getInitials(task.assignee)} size="xs" />
                              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                                {task.assignee ? task.assignee : getInitials(task.assignee)}
                              </Text>
                              {task.dueDate && (
                                <Tag variant="info" size="sm">
                                  Due: {task.dueDate}
                                </Tag>
                              )}
                            </Row>

                            <Select
                              label="Move task"
                              value={task.column ?? ''}
                              onChange={(value) => task.id && moveTask(task.id, value)}
                              options={(props.columns ?? [])
                                .filter((c) => c.id)
                                .map((c) => ({ value: c.id ?? '', label: c.name ?? c.id ?? 'Column' }))}
                            />
                          </Stack>
                        </Card>
                      );
                    })}
                  </Stack>

                  {addFormColumnId === columnId ? (
                    <Card padding="var(--ggui-spacing-3)" border shadow="none">
                      <Stack gap="var(--ggui-spacing-2)">
                        <Input
                          label="Task title"
                          value={newTaskTitle}
                          onChange={setNewTaskTitle}
                          placeholder="Enter task title"
                        />
                        <Select
                          label="Priority"
                          value={newTaskPriority}
                          onChange={(value) => setNewTaskPriority(value as 'low' | 'medium' | 'high')}
                          options={PRIORITY_OPTIONS}
                        />
                        <Row gap="var(--ggui-spacing-2)">
                          <Button variant="primary" size="sm" onClick={() => createTask()}>
                            Create
                          </Button>
                          <Button variant="ghost" size="sm" onClick={() => setAddFormColumnId(null)}>
                            Cancel
                          </Button>
                        </Row>
                      </Stack>
                    </Card>
                  ) : (
                    <Button variant="outline" size="sm" onClick={() => setAddFormColumnId(columnId)}>
                      Add Task
                    </Button>
                  )}
                </Stack>
              </Card>
            );
          })}
        </CardGrid>
        {actionError && <Alert variant="error" title="Action failed">{actionError}</Alert>}
      </Stack>
    </Container>

  );
}

