interface Props {
  product: { id?: string; name?: string; price?: number; currency?: string; rating?: number; reviewCount?: number; stock?: number; description?: string; specifications?: unknown[]; reviews?: unknown[] }; // Product object with id, name, price, currency, rating, stock, description, specifications[], reviews[]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user clicks Add to Cart. Payload: { productId, quantity } */
type ActionAddToCartPayload = { productId: string; quantity: number };





type SpecItem = { key?: string; value?: string };
type ReviewItem = { author?: string; rating?: number; text?: string; date?: string };

const getCurrencySymbol = (currency?: string): string => {
  if (!currency) return '$';
  const symbols: Record<string, string> = {
    USD: '$',
    EUR: '€',
    GBP: '£',
    JPY: '¥',
    INR: '₹',
    AUD: 'A$',
    CAD: 'C$',
  };
  return symbols[currency.toUpperCase()] || currency;
};

const StarRating = ({ rating }: { rating: number }) => {
  const safeRating = Math.max(0, Math.min(5, Math.round(rating)));
  return (
    <Row gap="var(--ggui-spacing-1)" aria-label={`${safeRating} out of 5 stars`}>
      {[1, 2, 3, 4, 5].map((star) => (
        <Text
          key={star}
          color={star <= safeRating ? 'var(--ggui-color-warning-500)' : 'var(--ggui-color-outline)'}
          variant="bodyLarge"
          is="span"
          aria-hidden="true"
        >
          ★
        </Text>
      ))}
    </Row>
  );
};


// Place helper components here if needed

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const addToCart = useAction<ActionAddToCartPayload>('addToCart'); // Called when user clicks Add to Cart. Payload: { productId, quantity }

  const safeStock = Math.max(0, Number(props.product?.stock || 0));
  const [quantity, setQuantity] = useState<number>(1);
  const [activeTab, setActiveTab] = useState<string>('description');

  useEffect(() => {
    if (safeStock <= 0) {
      setQuantity(1);
      return;
    }
    setQuantity((prev) => Math.min(Math.max(prev, 1), safeStock));
  }, [safeStock]);

  const currencySymbol = useMemo(() => getCurrencySymbol(props.product?.currency), [props.product?.currency]);
  const formattedPrice = useMemo(() => {
    const amount = Number(props.product?.price || 0);
    return `${currencySymbol}${amount.toFixed(2)}`;
  }, [currencySymbol, props.product?.price]);

  const specs = useMemo(() => (Array.isArray(props.product?.specifications) ? (props.product.specifications as SpecItem[]) : []), [props.product?.specifications]);
  const reviews = useMemo(() => (Array.isArray(props.product?.reviews) ? (props.product.reviews as ReviewItem[]) : []), [props.product?.reviews]);

  const isOutOfStock = safeStock <= 0;
  const isLowStock = safeStock > 0 && safeStock <= 5;

  const handleIncrement = useCallback(() => {
    setQuantity((prev) => Math.min(prev + 1, Math.max(1, safeStock)));
  }, [safeStock]);

  const handleDecrement = useCallback(() => {
    setQuantity((prev) => Math.max(1, prev - 1));
  }, []);

  const handleAddToCart = useCallback(() => {
    if (!props.product?.id || isOutOfStock) return;
    addToCart({ productId: props.product.id, quantity });
  }, [addToCart, isOutOfStock, props.product?.id, quantity]);

  const tabs = useMemo(
    () => [
      {
        key: 'description',
        label: 'Description',
        content: (
          <Card padding="var(--ggui-spacing-4)" border shadow="none">
            <Text color="var(--ggui-color-onSurfaceVariant)">
              {props.product?.description || 'No description available.'}
            </Text>
          </Card>
        ),
      },
      {
        key: 'specifications',
        label: 'Specifications',
        content: (
          <Card padding="var(--ggui-spacing-4)" border shadow="none">
            {specs.length === 0 ? (
              <Text color="var(--ggui-color-onSurfaceVariant)">No specifications available.</Text>
            ) : (
              <Table
                columns={[
                  { key: 'key', header: 'Specification' },
                  { key: 'value', header: 'Value' },
                ]}
                data={specs.map((item, index) => ({
                  id: `${item.key || 'spec'}-${index}`,
                  key: item.key || '—',
                  value: item.value || '—',
                }))}
                bordered
                compact
              />
            )}
          </Card>
        ),
      },
      {
        key: 'reviews',
        label: 'Reviews',
        content: (
          <Stack gap="var(--ggui-spacing-3)">
            {reviews.length === 0 ? (
              <Card padding="var(--ggui-spacing-4)" border shadow="none">
                <Text color="var(--ggui-color-onSurfaceVariant)">No reviews yet.</Text>
              </Card>
            ) : (
              reviews.map((review, index) => (
                <Card key={`${review.author || 'review'}-${index}`} padding="var(--ggui-spacing-4)" border shadow="none">
                  <Stack gap="var(--ggui-spacing-2)">
                    <Row justify="between" align="center">
                      <Text weight="medium">{review.author || 'Anonymous'}</Text>
                      <Text is="span" variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                        <time dateTime={review.date || ''}>{review.date || 'Unknown date'}</time>
                      </Text>
                    </Row>

                    <StarRating rating={Number(review.rating || 0)} />
                    <Text color="var(--ggui-color-onSurfaceVariant)">{review.text || 'No comment provided.'}</Text>
                  </Stack>
                </Card>
              ))
            )}
          </Stack>
        ),
      },
    ],
    [props.product?.description, reviews, specs],
  );

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-5)">
          <Stack gap="var(--ggui-spacing-5)">
            <Box>
              <Box style={{ display: 'grid', gap: 'var(--ggui-spacing-5)', gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))' }}>
                <Box
                  padding="var(--ggui-spacing-8)"
                  background="var(--ggui-color-primary-50)"
                  borderRadius="var(--ggui-shape-radius-lg)"
                  aria-label={`Product image placeholder for ${props.product?.name || 'Unnamed Product'}`}
                >
                  <Stack gap="var(--ggui-spacing-2)" align="center" justify="center">
                    <Icon name="image" size={32} color="var(--ggui-color-primary-600)" />
                    <Text align="center" weight="medium">{props.product?.name || 'Unnamed Product'}</Text>
                  </Stack>
                </Box>

                <Stack gap="var(--ggui-spacing-3)">
                  <Heading level={2}>{props.product?.name || 'Unnamed Product'}</Heading>
                  <Text size="2xl" weight="bold" color="var(--ggui-color-primary-700)">{formattedPrice}</Text>
                  <Row gap="var(--ggui-spacing-2)" align="center">
                    <StarRating rating={Number(props.product?.rating || 0)} />
                    <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                      ({Number(props.product?.reviewCount || reviews.length)})
                    </Text>
                  </Row>
                  <Row gap="var(--ggui-spacing-2)" align="center">
                    {isOutOfStock ? (
                      <Badge variant="error">Out of Stock</Badge>
                    ) : isLowStock ? (
                      <Badge variant="warning">Low Stock</Badge>
                    ) : (
                      <Badge variant="success">In Stock</Badge>
                    )}
                    <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                      {safeStock} available
                    </Text>
                  </Row>
                </Stack>
              </Box>
            </Box>

            <Tabs items={tabs} activeKey={activeTab} onChange={setActiveTab} />

            <Divider margin="var(--ggui-spacing-2)" />

            <Box>
              <Box style={{ display: 'grid', gap: 'var(--ggui-spacing-3)', gridTemplateColumns: 'repeat(auto-fit, minmax(220px, 1fr))', alignItems: 'end' }}>
                <Stack gap="var(--ggui-spacing-2)" role="group" aria-labelledby="quantity-label">
                  <Text id="quantity-label" variant="label">Quantity</Text>
                  <Row gap="var(--ggui-spacing-2)" align="center">
                    <Button variant="outline" onPress={handleDecrement} disabled={quantity <= 1} aria-label="Decrease quantity">
                      -
                    </Button>
                    <Box
                      paddingX="var(--ggui-spacing-4)"
                      paddingY="var(--ggui-spacing-2)"
                      background="var(--ggui-color-surfaceVariant)"
                      borderRadius="var(--ggui-shape-radius-md)"
                    >
                      <Text weight="medium">{quantity}</Text>
                    </Box>
                    <Button
                      variant="outline"
                      onPress={handleIncrement}
                      disabled={isOutOfStock || quantity >= safeStock}
                      aria-label="Increase quantity"
                    >
                      +
                    </Button>
                  </Row>
                </Stack>

                <Button variant="primary" onPress={handleAddToCart} disabled={isOutOfStock} fullWidth>
                  Add to Cart
                </Button>
              </Box>
            </Box>
          </Stack>
        </Card>
      </Stack>
    </Container>
  );
}

