import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>; // Array of stocks with symbol, name, price, change, changePercent
}


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: Updated price data for one or more stocks */
type StreamPriceUpdate = { symbol?: string; price?: number; change?: number; changePercent?: number };

/** Stream event: Market open/closed status update */
type StreamMarketStatus = { status?: 'open' | 'closed' | 'pre-market' | 'after-hours'; timestamp?: string };




// Place helper components here if needed
const formatPrice = (value?: number): string => `$${(value ?? 0).toFixed(2)}`;
const formatSigned = (value?: number): string => {
  const numberValue = value ?? 0;
  const sign = numberValue > 0 ? '+' : '';
  return `${sign}${numberValue.toFixed(2)}`;
};
const formatPercent = (value?: number): string => {
  const numberValue = value ?? 0;
  const sign = numberValue > 0 ? '+' : '';
  return `${sign}${numberValue.toFixed(2)}%`;
};

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract

  // Streams — real-time from agent (.latest, .all)
  const priceUpdate = useStream<StreamPriceUpdate>('priceUpdate'); // Updated price data for one or more stocks
  const marketStatus = useStream<StreamMarketStatus>('marketStatus'); // Market open/closed status update
  const [stockState, setStockState] = useState<Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>>(props.stocks ?? []);
  const [lastUpdated, setLastUpdated] = useState<string>(new Date().toLocaleTimeString());
  const [flashingSymbols, setFlashingSymbols] = useState<Record<string, number>>({});

  useEffect(() => {
    setStockState(props.stocks ?? []);
  }, [props.stocks]);

  useEffect(() => {
    const timer = setInterval(() => {
      setLastUpdated(new Date().toLocaleTimeString());
    }, 1000);

    return () => {
      clearInterval(timer);
    };
  }, []);

  useEffect(() => {
    if (!priceUpdate.latest?.symbol) {
      return;
    }

    const symbolKey = priceUpdate.latest.symbol;
    setStockState((prev) => {
      const hasExisting = prev.some((item) => item.symbol === symbolKey);
      if (!hasExisting) {
        return [
          ...prev,
          {
            symbol: priceUpdate.latest?.symbol,
            name: priceUpdate.latest?.symbol,
            price: priceUpdate.latest?.price,
            change: priceUpdate.latest?.change,
            changePercent: priceUpdate.latest?.changePercent,
          },
        ];
      }
      return prev.map((item) => {
        if (item.symbol !== symbolKey) {
          return item;
        }
        return {
          ...item,
          price: priceUpdate.latest?.price ?? item.price,
          change: priceUpdate.latest?.change ?? item.change,
          changePercent: priceUpdate.latest?.changePercent ?? item.changePercent,
        };
      });
    });

    setFlashingSymbols((prev) => ({ ...prev, [symbolKey]: Date.now() }));
    const timeout = setTimeout(() => {
      setFlashingSymbols((prev) => {
        const next = { ...prev };
        delete next[symbolKey];
        return next;
      });
    }, 700);

    return () => clearTimeout(timeout);
  }, [priceUpdate.latest]);

  const marketStatusLabel = marketStatus.latest?.status ?? 'open';
  const marketStatusVariant =
    marketStatusLabel === 'open' ? 'success' : marketStatusLabel === 'closed' ? 'error' : 'warning';

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Row justify="between" align="center" wrap>
          <Stack gap="var(--ggui-spacing-1)">
            <Heading level={1} color="var(--ggui-color-onSurface)">
              Market Watch
            </Heading>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
              Last Updated: {lastUpdated}
            </Text>
          </Stack>
          <Row gap="var(--ggui-spacing-2)" align="center">
            <Badge variant={marketStatusVariant}>
              {marketStatusLabel}
            </Badge>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
              Stream updates: {priceUpdate.all.length}
            </Text>
          </Row>
        </Row>

        {stockState.length === 0 ? (
          <Alert variant="info" title="No Stocks Available">
            No stock data is currently available.
          </Alert>
        ) : (
          <CardGrid columns={{ sm: 1, md: 2, lg: 3 }} gap={16}>
            {stockState.map((stock, index) => {
              const changeValue = stock.change ?? 0;
              const isPositive = changeValue >= 0;
              const colorToken = isPositive ? 'var(--ggui-color-success-600)' : 'var(--ggui-color-error-600)';
              const bgFlash = isPositive ? 'var(--ggui-color-success-100)' : 'var(--ggui-color-error-100)';
              const symbol = stock.symbol ?? `stock-${index}`;
              const isFlashing = Boolean(flashingSymbols[symbol]);

              return (
                <Card
                  key={symbol}
                  padding="var(--ggui-spacing-4)"
                  shadow="sm"
                  border
                  radius="lg"
                >
                  <Box
                    padding="var(--ggui-spacing-3)"
                    background={isFlashing ? bgFlash : 'var(--ggui-color-surfaceVariant)'}
                    borderRadius="var(--ggui-shape-radius-md)"
                  >
                    <Stack gap="var(--ggui-spacing-3)">
                      <Text
                        size="3xl"
                        weight="bold"
                        color="var(--ggui-color-onSurface)"
                      >
                        {stock.symbol ?? '—'}
                      </Text>
                      <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                        {stock.name ?? 'Unknown Company'}
                      </Text>
                      <Text size="2xl" weight="semibold" color="var(--ggui-color-onSurface)">
                        {formatPrice(stock.price)}
                      </Text>
                      <Row justify="between" align="center">
                        <Text variant="label" color={colorToken}>
                          {formatSigned(stock.change)}
                        </Text>
                        <Row gap="var(--ggui-spacing-1)" align="center">
                          <Text variant="label" color={colorToken}>
                            {isPositive ? '▲' : '▼'} {formatPercent(stock.changePercent)}
                          </Text>
                        </Row>
                      </Row>
                    </Stack>
                  </Box>
                </Card>
              );
            })}
          </CardGrid>
        )}
      </Stack>
    </Container>

  );
}

// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  initialProfile: { name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string }; // Pre-filled profile data for editing (all fields optional)
  avatarOptions: string[]; // Available avatar emojis to choose from
  roleOptions: string[]; // Available role options for the dropdown
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all profile data when user completes onboarding */
type ActionCompletePayload = { name: string; email: string; avatar: string; role: string; emailNotifications: boolean; theme: string };





// Place helper components here if needed

const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const complete = useAction<ActionCompletePayload>('complete'); // Called with all profile data when user completes onboarding
  const [currentStep, setCurrentStep] = useState(1);
  const [name, setName] = useState(props.initialProfile.name ?? '');
  const [email, setEmail] = useState(props.initialProfile.email ?? '');
  const [avatar, setAvatar] = useState(props.initialProfile.avatar ?? (props.avatarOptions[0] ?? '🙂'));
  const [role, setRole] = useState(props.initialProfile.role ?? (props.roleOptions[0] ?? 'Developer'));
  const [emailNotifications, setEmailNotifications] = useState(props.initialProfile.emailNotifications ?? true);
  const [theme, setTheme] = useState(props.initialProfile.theme === 'dark' ? 'dark' : 'light');
  const [submitted, setSubmitted] = useState(false);

  const emailValid = useMemo(() => EMAIL_REGEX.test(email.trim()), [email]);
  const stepOneValid = useMemo(() => name.trim().length > 0 && emailValid, [name, emailValid]);
  const stepTwoValid = useMemo(() => role.trim().length > 0 && (theme === 'light' || theme === 'dark'), [role, theme]);
  const canProceed = currentStep === 1 ? stepOneValid : currentStep === 2 ? stepTwoValid : true;
  const progressValue = useMemo(() => (currentStep / 3) * 100, [currentStep]);

  const handleNext = useCallback(() => {
    if (!canProceed) return;
    setCurrentStep((prev) => (prev < 3 ? prev + 1 : prev));
  }, [canProceed]);

  const handleBack = useCallback(() => {
    setCurrentStep((prev) => (prev > 1 ? prev - 1 : prev));
  }, []);

  const handleComplete = useCallback(() => {
    if (!stepOneValid || !stepTwoValid) return;
    const payload: ActionCompletePayload = {
      name: name.trim(),
      email: email.trim(),
      avatar,
      role,
      emailNotifications,
      theme,
    };
    complete(payload);
    setSubmitted(true);
  }, [stepOneValid, stepTwoValid, name, email, avatar, role, emailNotifications, theme, complete]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-6)" shadow="md" radius="lg">
          <Stack gap="var(--ggui-spacing-4)">
            <Row justify="between" align="center">
              <Heading level={3}>Onboarding Wizard</Heading>
              <Badge variant="primary">Step {currentStep} of 3</Badge>
            </Row>
            <Progress value={progressValue} max={100} size="md" />
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
              {currentStep === 1 ? 'Set up your basic profile details.' : currentStep === 2 ? 'Choose your preferences.' : 'Review and confirm your setup.'}
            </Text>
          </Stack>
        </Card>

        <Card padding="var(--ggui-spacing-6)" shadow="sm" radius="lg">
          <Box
            key={currentStep}
            style={{
              animation: 'ggui-fadeIn 200ms ease-out',
            }}
          >
            {currentStep === 1 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Step 1: Profile Setup</Heading>
                <Input
                  label="Name"
                  value={name}
                  onChange={setName}
                  required
                  placeholder="Enter your full name"
                  error={name.trim().length === 0 ? 'Name is required.' : undefined}
                />
                <Input
                  label="Email"
                  type="email"
                  value={email}
                  onChange={setEmail}
                  required
                  placeholder="you@example.com"
                  error={email.trim().length > 0 && !emailValid ? 'Please enter a valid email format.' : undefined}
                />
                <Box is="fieldset" style={{ border: 'none' }} padding="var(--ggui-spacing-1)">
                  <Text is="label" variant="label" color="var(--ggui-color-onSurfaceVariant)">
                    Choose Avatar
                  </Text>
                  <Row gap="var(--ggui-spacing-3)" wrap>
                    {props.avatarOptions.slice(0, 4).map((option) => {
                      const isActive = avatar === option;
                      return (
                        <Button
                          key={option}
                          variant={isActive ? 'primary' : 'outline'}
                          onClick={() => setAvatar(option)}
                          aria-checked={isActive}
                          role="radio"
                          aria-label={`Select avatar ${option}`}
                        >
                          <Text size="2xl" align="center">{option}</Text>
                        </Button>
                      );
                    })}
                  </Row>
                </Box>
              </Stack>
            )}

            {currentStep === 2 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Step 2: Preferences</Heading>
                <Select
                  label="Role"
                  value={role}
                  onChange={setRole}
                  options={props.roleOptions.map((option) => ({ value: option, label: option }))}
                  placeholder="Select your role"
                  required
                />
                <Toggle
                  label="Email notifications"
                  checked={emailNotifications}
                  onChange={setEmailNotifications}
                />
                <Toggle
                  label={`Theme: ${theme === 'dark' ? 'Dark' : 'Light'}`}
                  checked={theme === 'dark'}
                  onChange={(checked) => setTheme(checked ? 'dark' : 'light')}
                />
              </Stack>
            )}

            {currentStep === 3 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Step 3: Review & Confirm</Heading>
                <Alert variant="info" title="Review your details before submitting">
                  You can go back to edit any field.
                </Alert>
                <Card padding="var(--ggui-spacing-4)" shadow="none" border radius="md">
                  <Stack gap="var(--ggui-spacing-3)">
                    <Row align="center" gap="var(--ggui-spacing-3)">
                      <Avatar name={name || 'User'} size="md" />
                      <Text variant="bodyLarge">{avatar} {name || '—'}</Text>
                    </Row>
                    <Divider margin="var(--ggui-spacing-2)" />
                    <Text><Text is="span" weight="medium">Email:</Text> {email || '—'}</Text>
                    <Text><Text is="span" weight="medium">Role:</Text> {role || '—'}</Text>
                    <Text><Text is="span" weight="medium">Email Notifications:</Text> {emailNotifications ? 'On' : 'Off'}</Text>
                    <Text><Text is="span" weight="medium">Theme:</Text> {theme === 'dark' ? 'Dark' : 'Light'}</Text>
                  </Stack>
                </Card>
              </Stack>
            )}
          </Box>
        </Card>

        <Row justify="between" align="center">
          <Button variant="outline" onClick={handleBack} disabled={currentStep === 1}>
            Back
          </Button>
          <Row gap="var(--ggui-spacing-2)">
            {currentStep < 3 ? (
              <Button variant="primary" onClick={handleNext} disabled={!canProceed}>
                Next
              </Button>
            ) : (
              <>
                <Button variant="outline" onClick={() => setCurrentStep(2)}>Go Back</Button>
                <Button variant="primary" onClick={handleComplete} disabled={!stepOneValid || !stepTwoValid}>
                  Complete Setup
                </Button>
              </>
            )}
          </Row>
        </Row>

        {submitted && (
          <Alert variant="success" title="Setup complete">
            Your onboarding preferences have been saved.
          </Alert>
        )}
      </Stack>
    </Container>

  );
}
